-- ----------------------------------------------------------------------------
-- vw_language_candidates: Table: LanguageCandidates
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_language_candidates WITH (security_invoker = ON) AS
SELECT
  t.language_candidate_id,
  t.name,                                                                       -- Name of the language candidate being classified.
  t.is_language,                                                                -- The test answer that is intended to match the Family Feud answer to be "correct".
  calc_language_candidates_has_grammar(t.language_candidate_id) AS has_grammar, -- Does this candidate have a Grammar?  Generally follows candidates that have syntax also have grammar.
  t.has_syntax,                                                                 -- Does this language candidate have syntax and/or grammar?
  t.can_be_held,                                                                -- Is this candidate physical/material.  I.e. could it at least theoretically "be held"?
  calc_language_candidates_question(t.language_candidate_id) AS question,       -- Question that 100 random people could be asked, family feud style.
  calc_language_candidates_predicted_answer(t.language_candidate_id) AS predicted_answer,-- The predicted answer as the top most popular answer among those in the family feud polling pool.
  calc_language_candidates_prediction_predicates(t.language_candidate_id) AS prediction_predicates,
  calc_language_candidates_prediction_fail(t.language_candidate_id) AS prediction_fail,-- If the family feud answer does not match the chosen language candidates status then this explains what did not match. t also flags (in english) mismatch where a candidate is marked as BOTH open AND closed world which does not make sense.
  t.category,                                                                   -- The general high level category of the candidate.
  t.has_identity,                                                               -- Could this thing be assigned a guid, unique in the universe that would identify it globally?  Like a drivers license or social security number for a person.
  t.is_parsed,                                                                  -- Is the knowledge/information encoded in a form that requires parsing before meaning can be extracted?
  t.resolves_to_an_ast,                                                         -- Is the knowledge/information encoded in a form that requires parsing before meaning can be extracted?
  t.has_linear_decoding_pressure,
  t.is_stable_ontology_reference,
  t.is_live_ontology_editor,
  t.is_open_world,
  t.is_closed_world,
  calc_language_candidates_is_description_of(t.language_candidate_id) AS is_description_of,
  t.distance_from_concept,
  calc_language_candidates_is_open_closed_world_conflicted(t.language_candidate_id) AS is_open_closed_world_conflicted,
  t.dimensionality_while_editing,
  calc_language_candidates_relationship_to_concept(t.language_candidate_id) AS relationship_to_concept,
  t.model_object_facility_layer,
  t.sort_order
FROM language_candidates t;

-- ----------------------------------------------------------------------------
-- vw_is_everything_a_language: Table: IsEverythingALanguage
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_is_everything_a_language WITH (security_invoker = ON) AS
SELECT
  t.is_everything_a_language_id,
  t.name,
  t.argument_name,
  t.argument_category,
  t.step_type,
  t.statement,
  t.formalization,
  t.related_candidate_name,
  t.related_candidate_id,
  t.evidence_from_rulebook,
  t.notes
FROM is_everything_a_language t;

